 39	/**
 40	 * A utility class that evaluates the concept ranges
 41	 *
 42	 * @since 2.7.0
 43	 */
 44	public class ConceptReferenceRangeUtility {
 45	
 46		private final long NULL_DATE_RETURN_VALUE = -1;
 47	
 48		public ConceptReferenceRangeUtility() {
 49		}
 50	
 51		/**
 52		 * This method evaluates the given criteria against the provided {@link Obs}.
 53		 *
 54		 * @param criteria the criteria string to evaluate e.g. "$patient.getAge() > 1"
 55		 * @param obs The observation (Obs) object containing the values to be used in the criteria
 56		 *            evaluation.
 57		 * @return true if the criteria evaluates to true, false otherwise
 58		 */
 59		public boolean evaluateCriteria(String criteria, Obs obs) {
 60			if (obs == null) {
 61				throw new IllegalArgumentException("Failed to evaluate criteria with reason: Obs is null");
 62			}
 63	
 64			if (obs.getPerson() == null) {
 65				throw new IllegalArgumentException("Failed to evaluate criteria with reason: patient is null");
 66			}
 67	
 68			if (StringUtils.isBlank(criteria)) {
 69				throw new IllegalArgumentException("Failed to evaluate criteria with reason: criteria is empty");
 70			}
 71	
 72			return evaluateCriteria(criteria, new ConceptReferenceRangeContext(obs));
 73		}
 74	
 75		/**
 76		 * Evaluates criteria against a {@link ConceptReferenceRangeContext}. When the context was
 77		 * constructed from an Obs, {@code $obs} is available in the expression; otherwise only
 78		 * {@code $patient}, {@code $fn}, {@code $context}, {@code $date}, and {@code $encounter} are
 79		 * available.
 80		 *
 81		 * @param criteria the criteria string to evaluate
 82		 * @param context the evaluation context
 83		 * @return true if the criteria evaluates to true, false otherwise
 84		 * @since 3.0.0, 2.9.0, 2.8.5, 2.7.9
 85		 */
 86		public boolean evaluateCriteria(String criteria, ConceptReferenceRangeContext context) {
 87			if (context == null) {
 88				throw new IllegalArgumentException("Failed to evaluate criteria with reason: context is null");
 89			}
 90	
 91			if (context.getPerson() == null) {
 92				throw new IllegalArgumentException("Failed to evaluate criteria with reason: patient is null");
 93			}
 94	
 95			if (StringUtils.isBlank(criteria)) {
 96				throw new IllegalArgumentException("Failed to evaluate criteria with reason: criteria is empty");
 97			}
 98	
 99			VelocityContext velocityContext = new VelocityContext();
100			velocityContext.put("fn", this);
101			velocityContext.put("patient", HibernateUtil.getRealObjectFromProxy(context.getPerson()));
102			velocityContext.put("context", context);
103	
104			velocityContext.put("obs", context.getObs());
105			velocityContext.put("encounter", context.getEncounter());
106			velocityContext.put("date", context.getDate());
107	
108			VelocityEngine velocityEngine = new VelocityEngine();
109			try {
110				Properties props = new Properties();
111				props.put("runtime.log.logsystem.log4j.category", "velocity");
112				props.put("runtime.log.logsystem.log4j.logger", "velocity");
113				velocityEngine.init(props);
114			} catch (Exception e) {
115				throw new APIException("Failed to create the velocity engine: " + e.getMessage(), e);
116			}
117	
118			StringWriter writer = new StringWriter();
119			String wrappedCriteria = "#set( $criteria = " + criteria + " )$criteria";
120	
121			try {
122				velocityEngine.evaluate(velocityContext, writer, ConceptReferenceRangeUtility.class.getName(), wrappedCriteria);
123				return Boolean.parseBoolean(writer.toString());
124			} catch (ParseErrorException e) {
125				throw new APIException("An error occurred while evaluating criteria. Invalid criteria: " + criteria, e);
126			} catch (Exception e) {
127				throw new APIException("An error occurred while evaluating criteria: ", e);
128			}
129		}
