131		/**
132		 * Gets the latest Obs by concept.
133		 *
134		 * @param conceptRef can be either concept uuid or conceptMap's code and sourceName e.g
135		 *            "bac25fd5-c143-4e43-bffe-4eb1e7efb6ce" or "CIEL:1434"
136		 * @param person person to get obs for
137		 * @return Obs latest Obs
138		 */
139		public Obs getLatestObs(String conceptRef, Person person) {
140			if (person == null) {
141				return null;
142			}
143			Concept concept = Context.getConceptService().getConceptByReference(conceptRef);
144	
145			if (concept != null) {
146				List<Obs> observations = Context.getObsService().getObservations(Collections.singletonList(person), null,
147				    Collections.singletonList(concept), null, null, null, Collections.singletonList("dateCreated"), 1, null,
148				    null, null, false);
149	
150				return observations.isEmpty() ? null : observations.get(0);
151			}
152	
153			return null;
154		}
