165		/**
166		 * Retrieves the most relevant Obs for the given current Obs and conceptRef. If the current Obs
167		 * contains a valid value (coded, numeric, date, text e.t.c) and the concept in Obs is the same as
168		 * the supplied concept, the method returns the current Obs. Otherwise, it fetches the latest Obs
169		 * for the supplied concept and patient.
170		 *
171		 * @param currentObs the current Obs being evaluated
172		 * @return the most relevant Obs based on the current Obs, or the latest Obs if the current one has
173		 *         no valid value
174		 */
175		public Obs getCurrentObs(String conceptRef, Obs currentObs) {
176			Concept concept = Context.getConceptService().getConceptByReference(conceptRef);
177	
178			if (currentObs.getValueAsString(Locale.ENGLISH).isEmpty()
179			        && (concept != null && concept == currentObs.getConcept())) {
180				return currentObs;
181			} else {
182				return getLatestObs(conceptRef, currentObs.getPerson());
183			}
184		}
