186		/**
187		 * Gets the person's latest observation date for a given concept
188		 *
189		 * @param conceptRef can be either concept uuid or conceptMap's code and sourceName e.g
190		 *            "bac25fd5-c143-4e43-bffe-4eb1e7efb6ce" or "CIEL:1434"
191		 * @param person the person
192		 * @return the observation date
193		 * @since 2.7.8
194		 */
195		public Date getLatestObsDate(String conceptRef, Person person) {
196			Obs obs = getLatestObs(conceptRef, person);
197			if (obs == null) {
198				return null;
199			}
200	
201			Date date = obs.getValueDate();
202			if (date == null) {
203				date = obs.getValueDatetime();
204			}
205	
206			return date;
207		}
