209		/**
210		 * Checks if an observation's value coded answer is equal to a given concept
211		 *
212		 * @param conceptRef can be either concept uuid or conceptMap's code and sourceName e.g
213		 *            "bac25fd5-c143-4e43-bffe-4eb1e7efb6ce" or "CIEL:1434" for the observation's question
214		 * @param person the person
215		 * @param answerConceptRef can be either concept uuid or conceptMap's code and sourceName e.g
216		 *            "bac25fd5-c143-4e43-bffe-4eb1e7efb6ce" or "CIEL:1434" for the observation's coded
217		 *            answer
218		 * @return true if the given concept is equal to the observation's value coded answer
219		 * @since 2.7.8
220		 */
221		public boolean isObsValueCodedAnswer(String conceptRef, Person person, String answerConceptRef) {
222			Obs obs = getLatestObs(conceptRef, person);
223			if (obs == null) {
224				return false;
225			}
226	
227			Concept valudeCoded = obs.getValueCoded();
228			if (valudeCoded == null) {
229				return false;
230			}
231	
232			Concept answerConcept = Context.getConceptService().getConceptByReference(answerConceptRef);
233			if (answerConcept == null) {
234				return false;
235			}
236	
237			return valudeCoded.equals(answerConcept);
238		}
