416		/**
417		 * Returns whether the patient is the specified program on the specified date
418		 *
419		 * @param uuid of program
420		 * @param person the patient to test
421		 * @param onDate the date to test whether the patient is in the program
422		 * @return true if the patient is in the program on the specified date, false otherwise
423		 * @since 2.8.3
424		 */
425		public boolean isEnrolledInProgram(String uuid, Person person, Date onDate) {
426			if (person == null) {
427				return false;
428			}
429			if (!(person.getIsPatient())) {
430				return false;
431			}
432			return getPatientPrograms((Patient) person, onDate).stream().anyMatch(pp -> pp.getProgram().getUuid().equals(uuid));
433		}
434	
435		/**
436		 * Returns whether the patient is the specified program state on the specified date
437		 *
438		 * @param uuid of program state
439		 * @param person the patient to test
440		 * @param onDate the date to test whether the patient is in the program state
441		 * @return true if the patient is in the program state on the specified date, false otherwise
442		 * @since 2.8.3
443		 */
444		public boolean isInProgramState(String uuid, Person person, Date onDate) {
445			if (person == null) {
446				return false;
447			}
448			if (!(person.getIsPatient())) {
449				return false;
450			}
451	
452			List<PatientProgram> patientPrograms = getPatientPrograms((Patient) person, onDate);
453			List<PatientState> patientStates = new ArrayList<>();
454	
455			for (PatientProgram pp : patientPrograms) {
456				for (PatientState state : pp.getStates()) {
457					if (state.getActive(onDate)) {
458						patientStates.add(state);
459					}
460				}
461			}
462	
463			return patientStates.stream().anyMatch(ps -> ps.getState().getUuid().equals(uuid));
464		}
