 10	package org.openmrs;
 11	
 12	import java.util.Date;
 13	
 14	/**
 15	 * Holds the context needed to resolve a concept reference range for a given person and concept. The
 16	 * optional date field supports retrospective entry scenarios where date-relative criteria (e.g. age
 17	 * at encounter time) should be evaluated at a point in time other than today.
 18	 *
 19	 * @since 3.0.0, 2.9.0, 2.8.5, 2.7.9
 20	 */
 21	public class ConceptReferenceRangeContext {
 22	
 23		private final Person person;
 24	
 25		private final Concept concept;
 26	
 27		private final Date date;
 28	
 29		private final Encounter encounter;
 30	
 31		private final Obs obs;
 32	
 33		/**
 34		 * @param person the person to evaluate criteria against (required)
 35		 * @param concept the concept whose reference ranges to resolve (required)
 36		 * @param date the date at which to evaluate criteria, or null for today
 37		 */
 38		public ConceptReferenceRangeContext(Person person, Concept concept, Date date) {
 39			if (person == null) {
 40				throw new IllegalArgumentException("person is required");
 41			}
 42			if (concept == null) {
 43				throw new IllegalArgumentException("concept is required");
 44			}
 45			this.person = person;
 46			this.concept = concept;
 47			this.date = date;
 48			this.encounter = null;
 49			this.obs = null;
 50		}
 51	
 52		/**
 53		 * Convenience constructor that extracts person, concept, and obsDatetime from an existing Obs. The
 54		 * Obs is retained so that criteria expressions referencing {@code $obs} (e.g.
 55		 * {@code $obs.obsDatetime}) continue to work.
 56		 *
 57		 * @param obs the observation to extract context from
 58		 */
 59		public ConceptReferenceRangeContext(Obs obs) {
 60			if (obs == null) {
 61				throw new IllegalArgumentException("obs is required");
 62			}
 63			if (obs.getPerson() == null) {
 64				throw new IllegalArgumentException("person is required");
 65			}
 66			if (obs.getConcept() == null) {
 67				throw new IllegalArgumentException("concept is required");
 68			}
 69			this.person = obs.getPerson();
 70			this.concept = obs.getConcept();
 71			this.date = obs.getObsDatetime();
 72			this.encounter = obs.getEncounter();
 73			this.obs = obs;
 74		}
 75	
 76		/**
 77		 * Construct a context from an encounter and concept. The patient and encounter datetime are
 78		 * extracted from the encounter.
 79		 *
 80		 * @param encounter the encounter to extract context from (required)
 81		 * @param concept the concept whose reference ranges to resolve (required)
 82		 * @since 3.0.0, 2.9.0, 2.8.5, 2.7.9
 83		 */
 84		public ConceptReferenceRangeContext(Encounter encounter, Concept concept) {
 85			if (encounter == null) {
 86				throw new IllegalArgumentException("encounter is required");
 87			}
 88			if (encounter.getPatient() == null) {
 89				throw new IllegalArgumentException("person is required");
 90			}
 91			if (concept == null) {
 92				throw new IllegalArgumentException("concept is required");
 93			}
 94			this.person = encounter.getPatient();
 95			this.concept = concept;
 96			this.date = encounter.getEncounterDatetime();
 97			this.encounter = encounter;
 98			this.obs = null;
 99		}
100	
101		public Person getPerson() {
102			return person;
103		}
104	
105		public Concept getConcept() {
106			return concept;
107		}
108	
109		/**
110		 * @return the date at which to evaluate criteria, or null meaning "today"
111		 */
112		public Date getDate() {
113			return date;
114		}
115	
116		/**
117		 * @return the encounter if this context was constructed from one or from an Obs with an encounter,
118		 *         or null
119		 * @since 3.0.0, 2.9.0, 2.8.5, 2.7.9
120		 */
121		public Encounter getEncounter() {
122			return encounter;
123		}
124	
125		/**
126		 * @return the original Obs if this context was constructed from one, or null
127		 */
128		public Obs getObs() {
129			return obs;
130		}
131	}

